                os.Exit(1)
        }

        ctx := context.Background()
        store, err := embeddeddolt.New(ctx, absDir, *database, *branch)
        if err != nil {
                fmt.Fprintf(os.Stderr, "error: %v\n", err)
                os.Exit(1)
        }
        _ = store.Close()
        fmt.Println("ok")
}

