    db, cleanup, err := embeddeddolt.OpenSQL(ctx, dataDir, "beads", "main")
    if err != nil {
        fail("open raw embedded sql: %v", err)
    }

    _, err = db.ExecContext(ctx, `
        INSERT INTO issues (id, title, description, design, acceptance_criteria, notes, issue_type)
        VALUES ('bd-a', 'A', '', '', '', '', 'task'), ('bd-b', 'B', '', '', '', '', 'task')
    `)
    if err != nil {
