    }
    if _, err := db.ExecContext(ctx, "DROP TABLE IF EXISTS wisp_dependencies"); err != nil {
        fail("drop wisp_dependencies: %v", err)
    }

    tx, err := db.BeginTx(ctx, nil)
    if err != nil {
        fail("begin dependency tx: %v", err)
    }
    dep := &types.Dependency{IssueID: "bd-b", DependsOnID: "bd-a", Type: types.DepBlocks}
    err = issueops.AddDependencyInTx(ctx, tx, dep, "repro", issueops.AddDependencyOpts{})
    if err != nil {
