        fail("cycle detection failed with missing wisp_dependencies: %v", err)
    }
    if err := tx.Commit(); err != nil {
        fail("commit dependency tx: %v", err)
    }

    if _, err := db.ExecContext(ctx, "DROP TABLE IF EXISTS wisp_dependencies"); err != nil {
        fail("drop wisp_dependencies before reopen: %v", err)
    }
    if err := cleanup(); err != nil {
        fail("cleanup raw sql before reopen: %v", err)
    }

    reopened, err := embeddeddolt.New(ctx, beadsDir, "beads", "main")
    if err != nil {
        fail("reopen embedded store: %v", err)
    }
    if err := reopened.Close(); err != nil {
        fail("reopened embedded store close: %v", err)
    }

