    if err != nil {
        fail("open verify sql: %v", err)
    }
    defer verifyCleanup()
    for _, table := range []string{"wisps", "wisp_dependencies", "wisp_labels", "wisp_events", "wisp_comments"} {
        if !tableExists(ctx, verifyDB, table) {
            fail("ignored table %s was not recreated on embedded reopen", table)
        }
    }
    fmt.Println("embedded wisp table reproduction passed")
}
