// initialized embedded working sets and should not make permanent dependencies
// unusable.
func dependencyTableExistsInTx(ctx context.Context, tx *sql.Tx, table string) (bool, error) {
	//nolint:gosec // G201: table names come from AddDependencyOpts/internal constants
	rows, err := tx.QueryContext(ctx, fmt.Sprintf("SELECT 1 FROM %s LIMIT 0", table))
	if err != nil {
		if isTableNotExistError(err) {
